            If None, defaults to count and average score per group

    Returns:
        Dictionary mapping group_value to aggregated statistics
        Example: {"tech": {"count": 5, "avg_score": 0.85, "max_score": 0.95}}
    """
    # Initialize default aggregation functions if none provided
    if aggregation_funcs is None:
        aggregation_funcs = {
            "count": len,
            "avg_score": lambda x: sum(x) / len(x) if x else 0.0,
            "max_score": max,
            "min_score": min
        }

    # Initialize dictionary to store grouped results
    groups = defaultdict(list)

    # Iterate through each SearchResult
    for result in search_results:
        # Extract metadata value for the group_by_field
        group_value = result.metadata.get(group_by_field)

        # Use 'unknown' as group key if metadata value is missing
        group_key = group_value if group_value is not None else 'unknown'

        # Add result to the appropriate group
        groups[group_key].append(result)

    # Prepare final aggregated results dictionary
    aggregated_results = {}

    # Process each group
    for group_key, results in groups.items():
        group_stats = {}

        # Apply each aggregation function to the group's results
