                        else:
                            # Handle missing values by skipping them (they won't affect aggregation)
                            continue

                # Apply the aggregation function to the collected values
                if values:
                    try:
                        group_stats[field_name] = aggregation_func(values)
                    except Exception as e:
                        # Handle cases where aggregation might fail (e.g., empty list for non-count operations)
                        group_stats[field_name] = None
                else:
                    group_stats[field_name] = None

        aggregated_results[group_key] = group_stats

    return aggregated_results

